<?php $certificates = $certificates ?? []; $statuses = $statuses ?? []; $search = $search ?? ''; $status = $status ?? ''; $statusClasses = [0 => 'bg-secondary', 1 => 'bg-info', 2 => 'bg-success', 6 => 'bg-danger']; ?>
<div class="page-header"><h1>Non-Hazardous Certificates</h1></div>
<div class="card mb-3"><div class="card-body"><form method="get" action="/non-hazardous-certs" class="row g-3"><div class="col-md-6"><label class="form-label">Search</label><input name="search" class="form-control" value="<?= escapeHtml($search) ?>" placeholder="Certificate, buyer or remarks"></div><div class="col-md-3"><label class="form-label">Status</label><select name="status" class="form-select"><option value="" <?= $status === '' ? 'selected' : '' ?>>All</option><?php foreach ($statuses as $statusId => $statusName): ?><option value="<?= (int) $statusId ?>" <?= (string) $status === (string) $statusId ? 'selected' : '' ?>><?= escapeHtml($statusName) ?></option><?php endforeach; ?></select></div><div class="col-md-3 d-flex align-items-end gap-2"><button class="btn btn-primary">Search</button><a href="/non-hazardous-certs" class="btn btn-outline-secondary">Reset</a></div></form></div></div>
<div class="card"><div class="card-body"><div class="table-responsive"><table class="table table-striped datatable"><thead><tr><th>Certificate No</th><th>Date</th><th>Buyer</th><th>Status</th><th>Actions</th></tr></thead><tbody><?php foreach ($certificates as $certificate): ?><tr><td><?= escapeHtml($certificate['document_number']) ?></td><td><?= escapeHtml($certificate['document_date']) ?></td><td><?= escapeHtml($certificate['buyer_name'] ?? '') ?></td><td><span class="badge <?= escapeHtml($statusClasses[(int) $certificate['status']] ?? 'bg-secondary') ?>"><?= escapeHtml($statuses[(int) $certificate['status']] ?? 'Unknown') ?></span></td><td><a href="/non-hazardous-certs/<?= (int) $certificate['id'] ?>" class="btn btn-sm btn-outline-secondary">View</a> <button onclick="window.print()" class="btn btn-sm btn-outline-dark">Print</button><?php if (\App\Core\Session::get('role_name') === 'admin'): ?><form method="post" action="/non-hazardous-certs/<?= (int) $certificate['id'] ?>/delete" class="d-inline" onsubmit="return confirm('Are you sure you want to permanently delete this Non-Hazardous Certificate?');"><?= csrfToken() ?><button class="btn btn-sm btn-outline-danger">Delete</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
